#!/usr/bin/env node
// Regenerates the placeholder atlas image shipped with the SpriteCore plugin
// template. The placeholder is four 256x256 solid-colored frames packed into a
// single 512x512 WebP — one per state declared in agent.atlas.json (idle,
// thinking, happy, sad). Operators replace this image with real art and rerun
// `pnpm avatar:pack agent` (see docs/avatars/formats.md) once they have it.
//
// Run from the repo root:  node template/agent/regenerate-placeholder-atlas.mjs
//
// The generated bytes are committed to the repo so users do not need to run
// this script just to use the template — it only exists so we can regenerate
// when palette or layout changes.

import path from "node:path";
import { fileURLToPath } from "node:url";
import sharp from "sharp";

const here = path.dirname(fileURLToPath(import.meta.url));
const out = path.join(here, "agent.atlas.webp");

const FRAME = 256;
const ATLAS = 512;

// Frame ordering matches agent.atlas.json frames map (row-major, 2x2):
//   (0,0) idle      (1,0) thinking
//   (0,1) happy     (1,1) sad
const tiles = [
  { x: 0, y: 0, color: { r: 0x6b, g: 0x72, b: 0x80 }, label: "idle" }, // slate
  { x: FRAME, y: 0, color: { r: 0xea, g: 0xb3, b: 0x08 }, label: "thinking" }, // amber
  { x: 0, y: FRAME, color: { r: 0x22, g: 0xc5, b: 0x5e }, label: "happy" }, // green
  { x: FRAME, y: FRAME, color: { r: 0x3b, g: 0x82, b: 0xf6 }, label: "sad" }, // blue
];

const composites = await Promise.all(
  tiles.map(async ({ x, y, color }) => ({
    input: await sharp({
      create: {
        width: FRAME,
        height: FRAME,
        channels: 4,
        background: { ...color, alpha: 1 },
      },
    })
      .webp({ quality: 90 })
      .toBuffer(),
    left: x,
    top: y,
  })),
);

await sharp({
  create: {
    width: ATLAS,
    height: ATLAS,
    channels: 4,
    background: { r: 0, g: 0, b: 0, alpha: 0 },
  },
})
  .composite(composites)
  .webp({ quality: 90 })
  .toFile(out);

console.log(`wrote ${out}`);
